INSERT INTO `careers` (`id`, `job_reference_number`, `description`, `title`, `job_type`, `location`, `work_location`, `careers_job_details`, `status`, `created_at`, `updated_at`) VALUES
	(16, 'BSG2026499', 'As a <b>Sales Graphic</b>, you’ll be promoting a range of tech innovative devices, along with IT digital solution services. You’ll help businesses upgrade their technology, connect with clients, and deliver smarter solutions.', 'Sales Graphic', 'Full-time', 'South Triangle, Quezon City', 'Onsite', '<b>What You\'ll Do</b><br><ul style="list-style-type: disc; padding-left: 40px;"><li>Create eye-catching visuals, campaigns, and social media content.\n</li><li>Support sales with engaging marketing materials and client presentations.\n</li><li>Design stunning visuals, campaigns, and marketing collaterals.\n</li><li>Support and participate in sales inquiries and presentations.\n</li><li>Represent the company during trade shows, pitches, and client demos.\n</li><li>Design digital ads and campaigns that drive leads and awareness</li></ul><div><b><br></b></div><div><b>What We\'re Looking For</b><br><ul style="list-style-type: disc; padding-left: 40px;"><li>Graduate of Graphic Design, Multimedia, Marketing, IT, or related field.\n</li><li>Experience in sales, graphic design and marketing.\n</li><li>Familiar with laptops, tablets, digital displays, or IT services.\n</li><li>Proficient in Adobe Creative Suite (Photoshop, Illustrator, InDesign, Premiere, After Effects) or equivalent design tools.\n</li><li>Creative thinker with knowledge of digital marketing tools (Canva, Meta Ads, Google Ads, etc.).\n</li><li>Creative, adaptable, and detail-oriented, and enjoys working with technology.</li></ul></div>', 'Accepting_Applications', '2026-01-14 05:53:56', NULL),
	(25, 'BSG2026677', 'As a <b>Sales Marketing </b>Professional, You\'ll be promoting a range of tech devices such as Laptops, Tablets, digital Kiosks, interactive Boards, and smart Displays, along with IT services like CCTV installation and network system Setup. You\'ll help businesses upgrade their Technology, connect with Clients, and deliver smarter Solutions. Testing.', 'Sales Marketing', 'Full-time', 'South Triangle, Quezon City', 'Onsite', '<div><b>What You\'ll Do</b></div><ul style="list-style-type: disc; padding-left: 40px;"><li>Develop and implement marketing strategies tailored to IT devices and services.\n</li><li>Conduct market research and competitor analysis to identify business opportunities.\n</li><li>Create and manage marketing campaigns across digital and traditional platforms.\n</li><li>Generate and follow up on leads, prepare proposals, and negotiate sales contracts.\n</li><li>Coordinate with the technical team to ensure accurate product service information is conveyed to clients.\n</li><li>Represent the company in client meetings, trade shows, and product demonstrations.\n</li><li>Prepare sales forecasts, reports, and presentations for management.\n</li><li>Collaborate with management to design promotional materials and campaigns that align with company goals.\n</li><li>Provide after-sales support and maintain strong client relationships for repeat business.</li></ul><div><br></div><div><b>What We\'re Looking For</b></div><div><ul style="list-style-type: disc; padding-left: 40px;"><li>Bachelor\'s Degree in Business Administration, Marketing, IT, or related fields.\n</li><li>Experience in sales, marketing, business development, or technical support.\n</li><li>Familiar with laptops, tablets, digital displays, or IT services.\n</li><li>Confident communicator with strong presentation and persuasion skills.\n</li><li>MS Office proficiency, especially Excel and PowerPoint.\n</li><li>Strong organization and time management skills.\n</li><li>Creative thinker with knowledge of digital marketing tools.\n</li><li>Understanding of digital marketing and online sales strategies is a plus.\n</li><li>Motivated, results-oriented, and enjoys working with technology.</li></ul></div>', 'Accepting_Applications', '2026-01-19 02:37:56', NULL);
