INSERT INTO `faqs` (`id`, `pid`, `title`, `explanation`, `issue_id`, `products_id`, `is_all_devices`, `categories_id`, `is_deleted`, `created_at`, `updated_at`) VALUES
	(51, 'bf7b4b63-758e-4581-ab73-a6afff200b0f', 'Wi-fi or Network Not Connecting', '<b>Possible Causes:&nbsp;</b><div><ul style="list-style-type: disc; padding-left: 40px;"><li>Weak signal</li><li>Incorrect network settings&nbsp;</li><li>Software issue&nbsp;</li></ul><b>Basic Troubleshooting:</b>&nbsp;</div><div><ul style="list-style-type: disc; padding-left: 40px;"><li>Restart router and smart panel&nbsp;</li><li>Reconnect to Wi-Fi\nUse a LAN cable to test network&nbsp;</li><li>Reset Wi-fi module&nbsp;</li></ul></div>', NULL, NULL, 1, 7, 0, '2026-02-18 02:17:54', NULL),
	(52, '07266328-e9f7-42fa-a453-880a1040f7a0', 'Panel Won’t Power On', 'Check the main switch of the interactive smart panel is turned on Check the power cable and outlet Try a different power source Press and hold the power button for 10 seconds', NULL, NULL, 1, 7, 0, '2026-02-18 02:18:13', NULL),
	(53, '8310838c-d115-4b8b-8b28-7ffd4edc0ceb', 'Android System Freezes or Crashes', '<b>Possible Causes:&nbsp;</b><div><ul style="list-style-type: disc; padding-left: 40px;"><li>Low memory&nbsp;</li><li>Too many running apps&nbsp;</li><li>Outdated firmware&nbsp;</li></ul></div><div><b>Basic Troubleshooting:&nbsp;</b></div><div><ul style="list-style-type: disc; padding-left: 40px;"><li>Close unused apps&nbsp;</li><li>Restart the panel&nbsp;</li><li>Update system firmware&nbsp;</li></ul></div>', NULL, NULL, 1, 7, 0, '2026-02-18 02:18:51', NULL),
	(54, 'be073582-7903-482a-b76c-e1755c7e7b25', 'OPS PC Not Detected', '<b>Possible Causes:&nbsp;</b><div><ul style="list-style-type: disc; padding-left: 40px;"><li>OPS module not properly inserted&nbsp;</li><li>BIOS or driver issue&nbsp;</li><li>Power issue&nbsp;</li></ul></div><div><b>Basic Troubleshooting:&nbsp;</b></div><div><ul style="list-style-type: disc; padding-left: 40px;"><li>Reinsert the OPS module, then restart&nbsp;</li></ul></div>', NULL, NULL, 1, 7, 0, '2026-02-18 02:19:35', NULL),
	(55, '6e626dbc-5b3d-4d59-9ffe-c91a3ae6571a', 'Why is my Tablet slow?', '<ul style="list-style-type: disc; padding-left: 40px;"><li>Close unnecessary apps Restart the laptop&nbsp;</li><li>Update software and clear temporary files</li></ul>', NULL, NULL, 1, 24, 0, '2026-02-18 02:20:04', NULL),
	(57, '3f34dba8-caa4-4d8c-a021-12b64b5e9b90', 'No Touch / Ghost Touch', 'None', 74, 35, NULL, 7, 0, '2026-02-18 07:57:18', NULL);
