INSERT INTO `inquiries_reply` (`id`, `user_role`, `sender_name`, `subject`, `message_body`, `is_inbound`, `inquiries_id`, `created_at`) VALUES
	(39, 'Customer', 'Maria Santos', 'Server Warranty and Support', 'I would like to ask about the warranty period and support coverage for your enterprise servers.', 1, 21, '2025-12-23 02:03:32'),
	(42, 'Customer', 'Kevin Lim', 'Product Compatibility Question', 'Are your barcode scanners compatible with Windows 11 and existing POS systems?', 1, 22, '2025-12-23 07:53:23'),
	(43, 'Customer', 'Quotation Request for Printers', 'Quotation Request for Smart watches', 'Please send us a quotation for 5 multi-function Smart watches  .', 1, 23, '2025-12-23 08:07:16'),
	(45, 'Customer', 'Sophia Reyes', 'Delivery Timeline and Availability', 'What is the estimated delivery timeline for networking equipment, and are the items currently in stock?', 1, 25, '2025-12-23 08:24:36'),
	(46, 'Admin', 'John Doe', 'Delivery Timeline and Availability', 'Thank you for reaching out and for your interest in our networking equipment.\n\nWe are pleased to inform you that most of our standard networking items are currently in stock. For in-stock items, the estimated delivery timeline is typically 3–5 business days within Metro Manila and 5–7 business days for provincial areas, depending on the delivery location and logistics schedule.\n\nIf you have specific models or quantities in mind, please let us know so we can confirm availability and provide a more accurate delivery schedule. We would also be happy to prepare a formal quotation upon request.\n\nShould you have any further questions, feel free to contact us. We look forward to assisting you.\n\nBest regards,', 0, 25, '2025-12-23 08:25:36'),
	(50, 'Admin', 'John Doe', 'Server Warranty and Support', 'Thank you for your inquiry regarding our enterprise servers.\r\n\r\nOur enterprise servers come with a standard 3-year hardware warranty, which includes parts replacement and on-site support. In addition, we provide technical support during business hours, covering system diagnostics, troubleshooting, and configuration assistance.\r\n\r\nFor clients requiring extended coverage, we also offer optional support packages, such as 24/7 technical support, next-business-day or same-day on-site service, and extended warranty plans beyond the standard period.\r\n\r\nPlease let us know if you would like detailed documentation or a customized support plan based on your requirements. We would be happy to assist you further.\r\n\r\nBest regards,', 0, 21, '2026-01-05 05:59:06'),
	(51, 'Admin', 'John Doe', 'Product Compatibility Question', 'Thank you for your inquiry.\r\n\r\nYes, our barcode scanners are fully compatible with Windows 11. They support standard HID keyboard emulation and USB connectivity, which means they should work seamlessly with most systems that accept keyboard input.\r\n\r\nRegarding POS integration, our scanners are compatible with a wide range of popular POS software platforms. However, compatibility can vary depending on the specific software you’re using. To ensure full integration with your current POS system, could you please confirm the name and version of your POS software?\r\n\r\nOnce we have that information, we can provide more specific guidance and confirm complete compatibility.\r\n\r\nPlease let us know if you have any other questions or if you would like assistance selecting the right model for your setup.\r\n\r\nBest regards,', 0, 22, '2026-01-05 06:02:05'),
	(80, 'Admin', 'John Doe', 'Quotation Request for Smart watches', 'try', 0, 23, '2026-01-14 09:51:29'),
	(81, 'Admin', 'John Doe', 'Quotation Request for Smart watches', 'try', 0, 23, '2026-01-14 09:51:39'),
	(82, 'Admin', 'John Doe', 'Quotation Request for Smart watches', 'try', 0, 23, '2026-01-14 09:51:56'),
	(102, 'Customer', 'Dexter Jamero', 'Das', 'Da', 1, 42, '2026-03-10 03:44:29'),
	(103, 'Customer', 'John Ramirez', 'Smart Tv', 'May I kindly ask how much the movable TV stand costs? Also, could you please inform me when there is stock available again?', 1, 43, '2026-03-12 02:20:55');
INSERT INTO `issues` (`id`, `pid`, `name`, `categories_id`, `product_id`, `possible_solutions`, `is_publish`, `is_deleted`, `created_at`, `updated_at`) VALUES
	(54, 'ecd019eb-4aa2-4172-8f03-dbcd6a7e59bf', 'Blue Screen', 7, 29, '<ol><li>Restart your PC </li></ol><ul><li>Sometimes temporary glitch lang. </li></ul><ol start="2"><li>Remove external devices </li></ol><ul><li>USB, external HDD, printer, etc.</li><li>Restart after removing.</li></ul>', 0, 0, '2026-02-18 01:55:45', NULL),
	(55, '35aad918-decf-4730-b2bd-da8a71399495', 'Blue Screen', 7, 35, '<ol><li>Restart your PC </li></ol><ul><li>Sometimes temporary glitch lang. </li></ul><ol start="2"><li>Remove external devices </li></ol><ul><li>USB, external HDD, printer, etc.</li><li>Restart after removing.</li></ul>', 0, 0, '2026-02-18 01:56:03', NULL),
	(56, '83f1df0f-17be-489a-95b4-3a9875ff2922', 'Blue Screen', 7, 30, '<ol><li>Restart your PC </li></ol><ul><li>Sometimes temporary glitch lang. </li></ul><ol start="2"><li>Remove external devices </li></ol><ul><li>USB, external HDD, printer, etc.</li><li>Restart after removing.</li></ul>', 0, 0, '2026-02-18 01:56:21', NULL),
	(57, 'e4d4cd43-f3ba-45a0-9fa3-cf7f94cc483d', 'No Internet Connection', 27, 34, '<p><ol style="list-style-type: decimal; padding-left: 40px;"><li>Restart computer</li><li>Turn off router/modem</li><li>Wait 1–2 minutes</li><li>Turn router on → wait until lights stable</li><li>Connect again&nbsp;</li></ol></p>', 0, 0, '2026-02-18 02:03:09', NULL),
	(58, '43f13d4b-8195-4719-ba9a-9be8cc9119b1', 'Dead pixel', 7, 29, '<p><ol style="list-style-type: decimal; padding-left: 40px;"><li>Turn off monitor</li><li>Use soft cloth</li><li>Gently press area of pixel</li><li>Turn on screen while pressing</li></ol></p>', 0, 0, '2026-02-18 02:04:22', NULL),
	(59, '90c57480-e41d-4fd1-bef3-8659ffc62e31', 'Dead Pixel', 7, 35, '<p><ol style="list-style-type: decimal; padding-left: 40px;"><li>Turn off monitor</li><li>Use soft cloth</li><li>Gently press area of pixel</li><li>Turn on screen while pressing</li></ol></p>', 0, 0, '2026-02-18 02:04:41', NULL),
	(60, 'f4a5f8e5-e66d-49fa-9554-b3c8d29f9405', 'Dead Pixel', 7, 30, '<p><ol style="list-style-type: decimal; padding-left: 40px;"><li>Turn off monitor</li><li>Use soft cloth</li><li>Gently press area of pixel</li><li>Turn on screen while pressing</li></ol></p>', 0, 0, '2026-02-18 02:05:06', NULL),
