	(569, 'TK-99533', 'Customer', 'jamerodexter13@gmail.com', 'John Ramirez', 'My Wifi Does Not Working', 1, 0, '2026-03-12 02:26:00'),
	(570, 'TK-99533', 'Super admin', 'jamerodexter13@gmail.com', 'SuperBessee Admin', 'Hello! Sorry to hear that your WiFi is not working.\r\n\r\nPlease try restarting your router and reconnecting to the WiFi network. If the problem continues, kindly provide more details about the issue so we can assist you better.', 0, 0, '2026-03-12 05:07:10'),
	(571, 'TK-99533', 'Customer', 'jamerodexter13@gmail.com', 'John Ramirez', 'I try to restart the Wi-Fi but nothing happened', 1, 0, '2026-03-12 05:40:18'),
	(572, 'TK-99533', 'Super admin', 'jamerodexter13@gmail.com', 'SuperBessee Admin', 'Hello! Thank you for trying to restart your WiFi.\r\n\r\nSince the issue is still occurring, could you please provide the following details so we can assist you further:\r\n• Your location\r\n• The device you are using\r\n• When the problem started', 0, 0, '2026-03-12 05:41:37'),
	(574, 'TK-99533', 'Customer', 'jamerodexter13@gmail.com', 'John Ramirez', 'Location: Manila, Philippines\r\nDevice:  IPhone 14 and Windows 10 laptop\r\nWhen the problem started:  March 12, 2026, around 10:00 AM', 1, 0, '2026-03-12 05:52:47'),
	(576, 'TK-99533', 'Super admin', 'jamerodexter13@gmail.com', 'SuperBessee Admin', 'Ok, thank you. I will send the Job Order to you.', 0, 0, '2026-03-12 05:53:47'),
